pages.css:
:root {
  --ws-primary: #df7431;

  --font-300: "almoni-tzar3";
  --font-400: "almoni-tzar4";
  --font-700: "almoni-tzar7";
}

@font-face {
  font-family: "almoni-tzar3";
  src: url("../fonts/almoni-tzar-aaa-300.ttf");
}

@font-face {
  font-family: "almoni-tzar4";
  src: url("../fonts/almoni-tzar-aaa-400.ttf");
}

@font-face {
  font-family: "almoni-tzar7";
  src: url("../fonts/almoni-tzar-aaa-700.ttf");
}

body {
  direction: rtl;
  background-image: url("../images/Backgrounds/bg-stone.jpg");
  font-family: var(--font-400);
  /* background-position: center; */
}

a {
  color: unset;
  text-decoration: none;
  font-size: 1.2rem;
}

nav {
  position: fixed;
  z-index: 9999;
}

header {
  padding-top: 2.8rem;
  height: 100vh;
}

h1,
h2,
h3,
h4,
h5,
p,
a,
span {
  direction: rtl;
}

h1,
h2,
h3,
h4,
h5,
h6 {
  margin-bottom: 0rem;
}

.h2,
h2 {
  font-family: "almoni-tzar7";
  letter-spacing: 1.5;
  font-size: calc(3.5rem + 0.9vw);
}

@media (min-width: 1200px) {
  .h2,
  h2 {
    font-size: 4rem;
  }
}

.h4,
h4 {
  font-size: calc(2.075rem + 0.3vw);
}

@media (min-width: 1200px) {
  .h4,
  h4 {
    font-size: 2rem;
  }
}

/* WS.css Classes */
.ws-d-flex-center {
  display: flex;
  justify-content: center;
  align-items: center;
}

.ws-d-flex-start {
  display: flex;
  justify-content: start;
  align-items: center;
}

.ws-d-flex-end {
  display: flex;
  justify-content: end;
  align-items: center;
}

.gap-6 {
  gap: 6rem;
}

/* Hovers */

.line-hover {
  width: 0%;
  height: 1px;
  background-color: black;
  transition: width 0.7s ease;
}

.action-btn {
}

.action-btn:hover,
.join-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0px 2px 4px 2px rgba(0, 0, 0, 0.5);
}

.card-shadow {
}

.card-shadow:hover {
  transform: translateY(-2px);
  transform: scale(1.05);
  box-shadow: 0px 3px 6px -2px rgba(0, 0, 0, 0.5);
}

.scale-up {
  transition: transform 0.7s ease;
}

.scale-up:hover {
  transform: scale(1.1);
}

/*END Hovers*/

/* Single Icon Link*/
.cp-single-icon-link {
  display: flex;
  justify-content: center;
  align-items: center;
  flex-direction: column;
}

.cp-single-icon-link .note-hover {
  position: absolute;
  width: 100%;
  height: 100%;
  right: 0;
  left: 0;
  bottom: 13px;
  background-image: url("../images/Hover_imgs/NotesGuildaTransparent/1.png");
  background-position: center;
  background-size: contain;
  background-repeat: no-repeat;
  opacity: 0;
  transition: opacity 0.6s ease;
}

.cp-single-icon-link:hover .note-hover {
  opacity: 1;
}

.icon-box {
  padding: 2.5rem !important;
}

.icon-box img {
  position: relative;
  z-index: 1;
}

.cp-single-icon-link span {
  font-size: 1.5rem;
}

.cp-single-icon-link:hover .line-hover {
  width: 100%;
}
/*END Single icon link*/

/* Card */
.card {
  border: 0px solid black;
  border-radius: 10px;
  background-image: url("../images/Backgrounds/5.png");
  background-position: center;
  background-size: cover;
  background-repeat: no-repeat;
  display: flex !important;
  align-items: center;
  gap: 1px;
  transition: 0.6s ease;
  transition-property: box-shadow, transform;
  padding-bottom: 5px;
  text-align: center;
  /* display: flex; */
}

.ws-card-img {
  border-radius: 10px;
  border-bottom-left-radius: 0;
  border-bottom-right-radius: 0;
  width: 100%;
  height: 140px;
  background-image: url("https://placehold.co/600x400");
  background-position: center;
  background-size: cover;
  background-repeat: no-repeat;
}

.card h3 {
  text-align: center;
  padding: 5px 10px 0px 10px;
  margin-bottom: 0;
  font-size: 1.55rem;
  color: black;
}

.card h4 {
  padding: 5px 10px 0px 10px;
  font-size: 1.25rem;
}

.card-lg {
  width: 300px;
  height: 300px;
}

.card-sm {
  width: 250px;
  height: 200px;
  box-shadow: 0px 2px 7px -2px rgba(0, 0, 0, 0.5);
}

@media (max-width: 991px) {
  .card-sm {
    width: 200px;
    height: 200px;
  }
}

/* Btns */

/*.like-btn */
.like-btn {
  border-radius: 20px;
  border: 0;
  outline: 0;
  background-color: transparent;
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  align-content: center;
}

.heart-svg > * {
  transition-property: fill, stroke;
  transition: 0.8s ease;
}

.heart-svg path > * {
  stroke: stroke 0.8s ease;
}

.like-btn:hover .heart-svg,
.like-btn:hover .heart-svg path {
  fill: red;
  stroke: red;
}

/* action-btn*/
.action-btn {
  font-family: var(--font-700);
  background-color: var(--ws-primary);
  color: white;
  width: 120px;
  height: 40px;
  display: flex;
  justify-content: center;
  align-items: center;
  text-align: center;
  border-radius: 25px 25px 25px 25px;
  /* box-shadow: 0px 0px 2px 1px rgba(0, 0, 0, 0.5); */
  box-shadow: 0px 2px 4px 0px rgba(0, 0, 0, 0.5);
  line-height: 0;
  transition-property: box-shadow, transform;
  transition: 0.6s ease;
}

.join-btn {
  font-family: var(--font-400);
  font-size: 1.9rem;
  background-color: var(--ws-primary);
  color: white;
  width: 220px;
  height: 75px;
  display: flex;
  justify-content: center;
  align-items: center;
  text-align: center;
  border-radius: 25px 25px 25px 25px;
  /* box-shadow: 0px 0px 2px 1px rgba(0, 0, 0, 0.5); */
  box-shadow: 0px 2px 4px 0px rgba(0, 0, 0, 0.5);
  line-height: 0;
  transition-property: box-shadow, transform;
  transition: 0.6s ease;
  border: 5px solid #ffcf8ae0;
}

/* Sliders*/

.callk-slider {
  direction: ltr;
  width: 950px;
}

@media (max-width: 991px) {
  .callk-slider {
    width: 650px;
  }
}

@media (max-width: 665px) {
  .callk-slider {
    width: 300px;
  }
}

@media (max-width: 551px) {
  .header-menu {
    display: grid !important;
    grid-template-columns: 1fr 1fr;
    row-gap: 10px;
  }

  #header-logo {
    width: 370px;
  }
}

@media (max-width: 380px) {
  #header-logo {
    width: 300px;
    margin-top: 20px;
  }
}

.callk-item {
  margin: 25px 10px;
  /* z-index: 0; */
}

.info-grid {
  grid-template-columns: 1fr 1fr 1fr;
}

@media (max-width: 768px) {
  .info .row .col-md .card-sm:nth-child(2) {
    display: none !important;
  }

  .col-lines {
    display: none !important;
  }
}

.col-lines {
  position: absolute;
  justify-content: center;
  gap: 36.3%;
}

.col-line {
  width: 1px;
  height: 60vh;
  background-color: black;
}

.note-bg {
  background-image: url("../images/Backgrounds/Note-BG2.png");
  background-position: bottom center;
  background-size: cover;
}

@media (max-width: 1361px) {
  .note-bg {
    background-position: bottom;
    background-size: unset;
  }
}

.note2-bg {
  background-image: url("../images/Backgrounds/NoteBG-2&3\ trspt.png");
  background-repeat: no-repeat;
  background-position: center -420px;
  padding-top: 345px;
  margin-top: -280px;
  z-index: 0;
}

@media (min-width: 1370px) {
  .note2-bg {
    background-image: url("../images/Backgrounds/NoteBG-2&3\ trspt.png");
    background-repeat: no-repeat;
    background-position: center;
    padding-top: 516px;
    margin-top: -440px;
    z-index: 0;
    background-size: cover;
  }
}

@media (max-width: 767px) {
  .note2-bg {
    background-image: url("../images/Backgrounds/NoteBG-2&3\ trspt.png");
    background-repeat: no-repeat;
    background-position: center;
    padding-top: 516px;
    margin-top: -440px;
    z-index: 0;
    background-size: cover;
  }
}

.callk {
  z-index: 1;
}

@-webkit-keyframes pulseBtn {
  0% {
    -webkit-box-shadow: 0px 0px 0px 0px rgba(218, 125, 43);
  }
  100% {
    -webkit-box-shadow: 0px 0px 12px 0px rgba(218, 125, 43);
  }
}
@-moz-keyframes pulseBtn {
  0% {
    -moz-box-shadow: 0px 0px 0px 0px rgba(218, 125, 43);
  }
  100% {
    -moz-box-shadow: 0px 0px 12px 0px rgba(218, 125, 43);
  }
}

@keyframes pulseBtn {
  0% {
    box-shadow: 0px 0px 0px 0px rgba(81, 73, 255, 1);
  }
  100% {
    box-shadow: 0px 0px 20px 5px rgba(218, 125, 43);
  }
}

.join-btn {
  -webkit-animation-name: pulseBtn;
  -moz-animation-name: pulseBtn;
  animation-name: pulseBtn;

  -webkit-animation-duration: 0.9s;
  -moz-animation-duration: 0.9s;
  animation-duration: 0.9s;

  -webkit-animation-iteration-count: infinite;
  -moz-animation-iteration-count: infinite;
  animation-iteration-count: infinite;

  -webkit-animation-direction: alternate;
  -moz-animation-direction: alternate;
  animation-direction: alternate;

  -webkit-animation-timing-function: ease-in-out;
  -moz-animation-timing-function: ease-in-out;
  animation-timing-function: ease-in-out;
}

@-webkit-keyframes pulseBtn {
  0% {
    -webkit-box-shadow: 0px 0px 0px 0px rrgba(218, 125, 43);
    transform: scale(1);
  }
  100% {
    -webkit-box-shadow: 0px 0px 12px 0px rgba(218, 125, 43);
    transform: scale(1.03);
  }
}
@-moz-keyframes pulseBtn {
  0% {
    -moz-box-shadow: 0px 0px 0px 0px rgba(218, 125, 43);
    transform: scale(1);
  }
  100% {
    -moz-box-shadow: 0px 0px 12px 0px rgba(218, 125, 43);
    transform: scale(1.03);
  }
}

@keyframes pulseBtn {
  0% {
    box-shadow: 0px 0px 0px 0px rgba(218, 125, 43);
    transform: scale(1);
  }
  100% {
    box-shadow: 0px 0px 20px 5px rgba(218, 125, 43);
    transform: scale(1.03);
  }
}

.glow-btn .elementor-button {
  -webkit-animation-name: pulseBtn;
  -moz-animation-name: pulseBtn;
  animation-name: pulseBtn;

  -webkit-animation-duration: 0.9s;
  -moz-animation-duration: 0.9s;
  animation-duration: 0.9s;

  -webkit-animation-iteration-count: infinite;
  -moz-animation-iteration-count: infinite;
  animation-iteration-count: infinite;

  -webkit-animation-direction: alternate;
  -moz-animation-direction: alternate;
  animation-direction: alternate;

  -webkit-animation-timing-function: ease-in-out;
  -moz-animation-timing-function: ease-in-out;
  animation-timing-function: ease-in-out;
}

.cta-section {
  padding: 6rem 10px;
}

.st-bg {
  border-left: 1px solid orange !important;
}

.orange-bg,
.yellow-bg {
  background-repeat: no-repeat;
  background-size: cover;
  background-position: center;
}

.orange-bg {
  background-image: url("../images/Backgrounds/OrangeBG.png");
}

.yellow-bg {
  background-image: url("../images/Backgrounds/5.png");
}

.calender h2 {
  color: white;
}

.steps {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr 1fr 1fr;
}

.step-item {
  text-align: center;
  max-width: 350px;
}

.step-num {
}

.step-arrow {
  margin-bottom: 130px;
}

.step-arrow-mob {
  display: none;
}

@media (max-width: 991px) {
  .steps {
    display: flex;
    flex-direction: column;
    gap: 20px;
  }

  .step-arrow {
    margin-bottom: 0px;
  }

  .hide-mob-991 {
    display: none;
  }

  .step-arrow-mob {
    display: block;
    margin-bottom: 20px;
  }
}

.save-title a {
  text-decoration: underline;
  font-size: 1.4rem;
}

.step-num {
  top: 0;
  right: 0;
  font-size: 2.7rem;
  opacity: 0.7;
}

@media (max-width: 991px) {
  .step-num {
    right: 50px;
  }
}

.contact-grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr 1fr;
  gap: 100px;
}

@media (max-width: 1000px) {
  .contact-grid {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 480px) {
  .contact-grid {
    grid-template-columns: 1fr;
    gap: 50px;
  }
}

.contact-circle {
  border: 1px solid black;
  width: 170px;
  height: 170px;
  border-radius: 150px;
  background-position: center;
  background-size: cover;
  background-repeat: no-repeat;
}

.contact-item {
  gap: 10px;
}

.contact-item a {
  transition: transform 0.7s ease;
}

.contact-item a:hover {
  transform: scale(1.2);
}

.contact-item h3 {
  font-size: 2.5rem;
}

.contact-item h4 {
  font-size: 1.5rem;
}

.sponsers h2 {
  color: white;
}

/*slider patner*/
.partner-slider {
  display: flex;
  justify-content: center;
  direction: ltr;
}
.partner-slider div img {
  width: 170px;
}
.partner-slider img {
  max-width: 100%;
  height: auto;
  margin: 0 20px; /* Adjust spacing between logos */
}

.partner-slider .slick-list .slick-track {
  display: flex;
  justify-content: center;
  align-items: center;
}

footer {
  position: relative;
}

.footer-overlay {
  position: absolute;
  width: 100%;
  height: 100%;
  background-color: rgba(0, 0, 0, 0.5);
  z-index: -1;
}

.social-links {
  gap: 5px;
}

.social-links img {
  width: 30px;
}

footer .fl .links a {
  color: white;
  transition: transform 0.7s ease;
}

footer .fl .links a:hover {
  transform: scale(1.2);
}

@media (max-width: 480px) {
  .links {
    flex-direction: column;
    justify-content: center;
    align-items: center;
  }
}

/* ==================== */
/* Nav Links            */
/* ==================== */

.nav-link-item {
  font-family: var(--font-700);
  font-size: 1.3rem;
  color: black;
  transition: color 0.4s ease;
  position: relative;
}

.nav-link-item::after {
  content: "";
  position: absolute;
  bottom: -2px;
  right: 0;
  width: 0%;
  height: 1px;
  background-color: var(--ws-primary);
  transition: width 0.5s ease;
}

.nav-link-item:hover::after,
.nav-link-item.active::after {
  width: 100%;
}

.nav-link-item:hover,
.nav-link-item.active {
  color: var(--ws-primary);
}

/* ==================== */
/* Page Header (inner)  */
/* ==================== */

.page-header {
  padding-top: 5rem;
  padding-bottom: 2rem;
  min-height: auto;
  height: auto;
  gap: 1rem;
}

.blog-subtitle {
  font-family: var(--font-400);
  font-size: 1.4rem;
  text-align: center;
  color: #555;
}

/* ==================== */
/* Blog Page            */
/* ==================== */

.blog-grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 30px;
}

@media (max-width: 991px) {
  .blog-grid {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 600px) {
  .blog-grid {
    grid-template-columns: 1fr;
  }
}

.card-blog {
  width: 100%;
  height: auto;
  min-height: 380px;
}

.card-blog .ws-card-img {
  height: 180px;
}

.card-body-blog {
  padding: 12px 15px;
  display: flex;
  flex-direction: column;
  gap: 6px;
  width: 100%;
  text-align: right;
}

.card-body-blog h3 {
  text-align: right;
  font-size: 1.4rem;
  padding: 0;
}

.card-category {
  font-family: var(--font-700);
  font-size: 0.9rem;
  color: var(--ws-primary);
}

.card-date {
  font-size: 0.9rem;
  color: #888;
}

.card-excerpt {
  font-size: 1rem;
  color: #555;
  line-height: 1.5;
  margin: 0;
}

.card-blog .like-btn {
  align-self: flex-start;
}

/* ==================== */
/* Blog Post Page       */
/* ==================== */

.post-container {
  max-width: 800px;
}

.post-meta {
  gap: 0.5rem;
  padding-bottom: 2rem;
}

.post-title {
  font-family: var(--font-700);
  font-size: calc(2.5rem + 0.5vw);
  text-align: center;
  line-height: 1.3;
}

@media (min-width: 1200px) {
  .post-title {
    font-size: 2.8rem;
  }
}

.post-featured-img {
  width: 100%;
  height: 400px;
  border-radius: 10px;
  background-image: url("https://placehold.co/1200x600");
  background-position: center;
  background-size: cover;
  background-repeat: no-repeat;
}

@media (max-width: 600px) {
  .post-featured-img {
    height: 220px;
  }
}

.post-content {
  padding: 3rem 0;
}

.post-content p {
  font-size: 1.2rem;
  line-height: 1.9;
  color: #333;
  margin-bottom: 1.5rem;
}

.post-content h2 {
  font-family: var(--font-700);
  font-size: 2rem;
  margin-top: 2.5rem;
  margin-bottom: 1rem;
}

.post-cta {
  margin-top: 3rem;
  padding: 3rem 2rem;
  background-image: url("../images/Backgrounds/5.png");
  background-size: cover;
  background-position: center;
  border-radius: 10px;
  gap: 1.5rem;
  text-align: center;
}

.post-cta p {
  font-size: 1.3rem;
  max-width: 550px;
}

/* ==================== */
/* About Page           */
/* ==================== */

.about-section {
  padding: 3rem 0;
}

.about-content {
  max-width: 900px;
  margin: 0 auto;
}

.about-block {
  text-align: center;
  gap: 1.5rem;
}

.about-block p {
  font-size: 1.25rem;
  line-height: 1.9;
  color: #333;
  max-width: 750px;
}

.about-services-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 40px;
}

@media (max-width: 768px) {
  .about-services-grid {
    grid-template-columns: 1fr;
  }
}

.about-service-item {
  text-align: center;
  gap: 10px;
  padding: 1.5rem;
  border-radius: 10px;
  background-image: url("../images/Backgrounds/5.png");
  background-size: cover;
  background-position: center;
  transition: transform 0.6s ease, box-shadow 0.6s ease;
}

.about-service-item:hover {
  transform: translateY(-4px);
  box-shadow: 0px 4px 12px -2px rgba(0, 0, 0, 0.2);
}

.about-service-item h3 {
  font-family: var(--font-700);
  font-size: 1.8rem;
}

.about-service-item p {
  font-size: 1.1rem;
  line-height: 1.7;
  color: #444;
  max-width: 400px;
}

.about-cta-text {
  font-size: 1.25rem;
  max-width: 650px;
  line-height: 1.8;
  color: #333;
}

:root {
  --ws-primary: #df7431;

  --font-300: "almoni-tzar3";
  --font-400: "almoni-tzar4";
  --font-700: "almoni-tzar7";
}

@font-face {
  font-family: "almoni-tzar3";
  src: url("../fonts/almoni-tzar-aaa-300.ttf");
}

@font-face {
  font-family: "almoni-tzar4";
  src: url("../fonts/almoni-tzar-aaa-400.ttf");
}

@font-face {
  font-family: "almoni-tzar7";
  src: url("../fonts/almoni-tzar-aaa-700.ttf");
}

body {
  direction: rtl;
  background-image: url("../images/Backgrounds/bg-stone.jpg");
  font-family: var(--font-400);
  /* background-position: center; */
}

a {
  color: unset;
  text-decoration: none;
  font-size: 1.2rem;
}

nav {
  position: fixed;
  z-index: 9999;
}

header {
  padding-top: 2.8rem;
  height: 100vh;
}

h1,
h2,
h3,
h4,
h5,
p,
a,
span {
  direction: rtl;
}

h1,
h2,
h3,
h4,
h5,
h6 {
  margin-bottom: 0rem;
}

.h2,
h2 {
  font-family: "almoni-tzar7";
  letter-spacing: 1.5;
  font-size: calc(3.5rem + 0.9vw);
}

@media (min-width: 1200px) {
  .h2,
  h2 {
    font-size: 4rem;
  }
}

.h4,
h4 {
  font-size: calc(2.075rem + 0.3vw);
}

@media (min-width: 1200px) {
  .h4,
  h4 {
    font-size: 2rem;
  }
}

