  justify-content: center;
  flex-wrap: wrap;
  align-content: center;
}

.heart-svg > * {
  transition-property: fill, stroke;
  transition: 0.8s ease;
}

.heart-svg path > * {
  stroke: stroke 0.8s ease;
}

.like-btn:hover .heart-svg,
.like-btn:hover .heart-svg path {
  fill: red;
  stroke: red;
}

