@-webkit-keyframes pulseBtn {
  0% {
    -webkit-box-shadow: 0px 0px 0px 0px rgba(218, 125, 43);
  }
  100% {
    -webkit-box-shadow: 0px 0px 12px 0px rgba(218, 125, 43);
  }
}
@-moz-keyframes pulseBtn {
  0% {
    -moz-box-shadow: 0px 0px 0px 0px rgba(218, 125, 43);
  }
  100% {
    -moz-box-shadow: 0px 0px 12px 0px rgba(218, 125, 43);
  }
}

@keyframes pulseBtn {
  0% {
    box-shadow: 0px 0px 0px 0px rgba(81, 73, 255, 1);
  }
  100% {
    box-shadow: 0px 0px 20px 5px rgba(218, 125, 43);
  }
}

.join-btn {
  -webkit-animation-name: pulseBtn;
  -moz-animation-name: pulseBtn;
  animation-name: pulseBtn;

  -webkit-animation-duration: 0.9s;
  -moz-animation-duration: 0.9s;
  animation-duration: 0.9s;

  -webkit-animation-iteration-count: infinite;
  -moz-animation-iteration-count: infinite;
  animation-iteration-count: infinite;

  -webkit-animation-direction: alternate;
  -moz-animation-direction: alternate;
  animation-direction: alternate;

  -webkit-animation-timing-function: ease-in-out;
  -moz-animation-timing-function: ease-in-out;
  animation-timing-function: ease-in-out;
}

@-webkit-keyframes pulseBtn {
  0% {
    -webkit-box-shadow: 0px 0px 0px 0px rrgba(218, 125, 43);
    transform: scale(1);
  }
  100% {
    -webkit-box-shadow: 0px 0px 12px 0px rgba(218, 125, 43);
    transform: scale(1.03);
  }
}
@-moz-keyframes pulseBtn {
  0% {
    -moz-box-shadow: 0px 0px 0px 0px rgba(218, 125, 43);
    transform: scale(1);
  }
  100% {
    -moz-box-shadow: 0px 0px 12px 0px rgba(218, 125, 43);
    transform: scale(1.03);
  }
}

@keyframes pulseBtn {
  0% {
    box-shadow: 0px 0px 0px 0px rgba(218, 125, 43);
    transform: scale(1);
  }
  100% {
    box-shadow: 0px 0px 20px 5px rgba(218, 125, 43);
    transform: scale(1.03);
  }
}

.glow-btn .elementor-button {
  -webkit-animation-name: pulseBtn;
  -moz-animation-name: pulseBtn;
  animation-name: pulseBtn;

  -webkit-animation-duration: 0.9s;
  -moz-animation-duration: 0.9s;
  animation-duration: 0.9s;

  -webkit-animation-iteration-count: infinite;
  -moz-animation-iteration-count: infinite;
  animation-iteration-count: infinite;

  -webkit-animation-direction: alternate;
  -moz-animation-direction: alternate;
  animation-direction: alternate;

  -webkit-animation-timing-function: ease-in-out;
  -moz-animation-timing-function: ease-in-out;
  animation-timing-function: ease-in-out;
}

